interface Person {
  name: string;
  title: string;
}

templateData: TreeNode<Person>[] = [
  {
    label: 'John Smith',
    data: { name: 'John Smith', title: 'CEO' },
    expanded: true,
    children: [
      { label: 'Sarah Johnson', data: { name: 'Sarah Johnson', title: 'CTO' } },
      { label: 'David Wilson', data: { name: 'David Wilson', title: 'CFO' } },
    ],
  },
];

